62	    constant TickCycles_c          : real    := ceil(ClkFrequency_g/TargetTickFrequency_c);
63	    constant ActualTickFrequency_c : real    := ClkFrequency_g/TickCycles_c;
64	    constant DebounceTicks_c       : integer := integer(ceil(DebounceTime_g*ActualTickFrequency_c));
65	    constant UseStrobeDiv_c        : boolean := integer(TickCycles_c) >= 2;
