90	    assert compareNoCase(Mode_g, "GLITCH_FILTER") or compareNoCase(Mode_g, "LOW_LATENCY")
91	        report errorMessage(EntityName_c, "Illegal Mode_g - " & Mode_g)
92	        severity failure;
