124	            if compareNoCase(Mode_g, "GLITCH_FILTER") then
125	                -- Only forward signal once stable
126	                if r.IsStable(i) = '1' then
127	                    v.DataOut(i) := r.LastState(i);
128	                end if;
129	            end if;
130	
131	            -- LOW_LATENCY mode
132	            if compareNoCase(Mode_g, "LOW_LATENCY") then
133	                -- Forward new state whenever signal is stable (including first edge)
134	                if r.IsStable(i) = '1' then
