26	-- vunit: run_all_in_same_sim
27	entity olo_intf_debounce_tb is
28	    generic (
29	        IdleLevel_g         : integer range 0 to 1 := 0;
30	        DebounceCycles_g    : integer              := 200;
31	        Mode_g              : string               := "LOW_LATENCY";
32	        runner_cfg          : string
33	    );
34	end entity;
35	
36	architecture sim of olo_intf_debounce_tb is
37	
38	    -----------------------------------------------------------------------------------------------
39	    -- Constants
40	    -----------------------------------------------------------------------------------------------
41	    constant DataWidth_c : integer := 2;
42	
43	    -----------------------------------------------------------------------------------------------
44	    -- TB Defnitions
45	    -----------------------------------------------------------------------------------------------
46	    constant IdleLevel_c     : std_logic := choose(IdleLevel_g = 0, '0', '1');
47	    constant Clk_Frequency_c : real      := 100.0e6;
48	    constant Clk_Period_c    : time      := (1 sec) / Clk_Frequency_c;
49	    constant Time_Debounce_c : time      := Clk_Period_c*DebounceCycles_g;
50	    constant IsLowLat_c      : boolean   := (Mode_g = "LOW_LATENCY");
51	    constant MaxPropDelay_c  : time      := 5*Clk_Period_c;
52	    constant MaxDetTime_c    : time      := Time_Debounce_c*1.1+MaxPropDelay_c;
53	
54	    signal BounceOhter : boolean := false;
55	
56	    -----------------------------------------------------------------------------------------------
57	    -- Interface Signals
58	    -----------------------------------------------------------------------------------------------
59	    signal Clk       : std_logic                                  := '0';
60	    signal Rst       : std_logic                                  := '1';
61	    signal DataAsync : std_logic_vector(DataWidth_c - 1 downto 0) := (others => IdleLevel_c);
62	    signal DataOut   : std_logic_vector(DataWidth_c - 1 downto 0);
63	
64	begin
65	
66	    -----------------------------------------------------------------------------------------------
67	    -- DUT
68	    -----------------------------------------------------------------------------------------------
69	    i_dut : entity olo.olo_intf_debounce
70	        generic map (
71	            ClkFrequency_g  => Clk_Frequency_c,
72	            DebounceTime_g  => (1.0/Clk_Frequency_c)*real(DebounceCycles_g),
73	            Width_g         => DataWidth_c,
74	            IdleLevel_g     => IdleLevel_c,
75	            Mode_g          => Mode_g
76	        )
77	        port map (
78	            Clk         => Clk,
79	            Rst         => Rst,
80	            DataAsync   => DataAsync,
81	            DataOut     => DataOut
82	        );
83	
84	    -----------------------------------------------------------------------------------------------
85	    -- Clock
86	    -----------------------------------------------------------------------------------------------
87	    Clk <= not Clk after 0.5 * Clk_Period_c;
88	
89	    -----------------------------------------------------------------------------------------------
90	    -- TB Control
91	    -----------------------------------------------------------------------------------------------
92	    -- TB is not very vunit-ish because it is a ported legacy TB
93	    test_runner_watchdog(runner, 1 ms);
94	
95	    p_control : process is
96	        constant RstVal_c    : std_logic_vector(DataWidth_c - 1 downto 0) := (others => IdleLevel_c);
97	        variable StartTime_v : time;
98	    begin
99	        test_runner_setup(runner, runner_cfg);
100	
101	        while test_suite loop
102	
103	            -- *** Reset ***
104	            Rst <= '1';
105	            wait until rising_edge(Clk);
106	            Rst <= '0';
107	            wait until rising_edge(Clk);
108	
109	            if run("ResetValue") then
110	                check_equal(DataOut, RstVal_c, "Data not reset");
111	            end if;
112	
113	            if run("SlowPulse") then
114	                -- Check initial state
115	                check_equal(DataOut(0), IdleLevel_c, "Wrong initial value");
116	                -- Toggle value
117	                DataAsync(0) <= not IdleLevel_c;
118	                -- Wait until value is detected
119	                if IsLowLat_c then
120	                    wait for MaxPropDelay_c;
121	                else
122	                    wait for MaxDetTime_c;
123	                end if;
124	                check_equal(DataOut(0), not IdleLevel_c, "Pulse Value wrong");
125	                -- wait for minimum time
126	                wait for MaxDetTime_c;
127	                -- End of pulse
128	                DataAsync(0) <= IdleLevel_c;
129	                -- Wait until new value is detected
130	                if IsLowLat_c then
131	                    wait for MaxPropDelay_c;
132	                else
133	                    wait for MaxDetTime_c;
134	                end if;
135	                check_equal(DataOut(0), IdleLevel_c, "Idle Value wrong after pulse");
136	            end if;
137	
138	            if run("ShortPulse") then
139	                StartTime_v := now;
140	                -- Check initial state
141	                check_equal(DataOut(0), IdleLevel_c, "Wrong initial value");
142	                -- Toggle value
143	                DataAsync(0) <= not IdleLevel_c;
144	                -- Wait until value is detected for low latency
145	                wait for MaxPropDelay_c;
146	                if IsLowLat_c then
147	                    check_equal(DataOut(0), not IdleLevel_c, "Pulse Value wrong");
148	                else
149	                    check_equal(DataOut(0), IdleLevel_c, "Pulse Value wrong"); -- In GLTCH_FILTER mode we don't detect the pulse
150	                end if;
151	                -- End of pulse
152	                DataAsync(0) <= IdleLevel_c;
153	                -- Wait until new value is detected
154	                wait for Time_Debounce_c*0.8;
155	                if IsLowLat_c then
156	                    check_equal(DataOut(0), not IdleLevel_c, "After Pulse Value wrong");
157	                else
158	                    check_last_activity(DataOut(0), Time_Debounce_c*0.8, choose(IdleLevel_c='0', 0, 1), "Value after pulse 1");
159	                end if;
160	                -- After pulse value
161	                wait for Time_Debounce_c*0.3+MaxPropDelay_c;
162	                check_equal(DataOut(0), IdleLevel_c, "After Pulse Value wrong 2");
163	            end if;
164	
165	            -- Bouncy Pulse
166	            if run("BouncPulse") then
167	                -- Check initial state
168	                check_equal(DataOut(0), IdleLevel_c, "Wrong initial value");
169	                -- Toggle value
170	                DataAsync(0) <= not IdleLevel_c;
171	
172	                -- bounce phase
173	                for i in 0 to  5 loop
174	                    -- Check value
175	                    if IsLowLat_c then
176	                        wait for MaxPropDelay_c;
177	                        check_equal(DataOut(0), not IdleLevel_c, "Pulse Value wrong during bounce");
178	                        wait for Time_Debounce_c*0.75-MaxPropDelay_c;
179	                    else
180	                        check_equal(DataOut(0), IdleLevel_c, "Pulse Detected Early during bounce");
181	                        wait for Time_Debounce_c*0.75;
182	                    end if;
183	                    -- Toggle Signal
184	                    DataAsync(0) <= not DataAsync(0);
185	                end loop;
186	
187	                -- wait for minimum time
188	                wait for MaxDetTime_c;
189	                check_equal(DataOut(0), not IdleLevel_c, "Pulse Value wrong");
190	                -- End of pulse
191	                DataAsync(0) <= IdleLevel_c;
192	
193	                -- bounce phase
194	                for i in 0 to  5 loop
195	                    -- Check value
196	                    if IsLowLat_c then
197	                        wait for MaxPropDelay_c;
198	                        check_equal(DataOut(0), IdleLevel_c, "Pulse not removed during after bounce phase");
199	                        wait for Time_Debounce_c*0.75-MaxPropDelay_c;
200	                    else
201	                        check_equal(DataOut(0), not IdleLevel_c, "Pulse removed during after bounce phase");
202	                        wait for Time_Debounce_c*0.75;
203	                    end if;
204	                    -- Toggle Signal
205	                    DataAsync(0) <= not DataAsync(0);
206	                end loop;
207	
208	                wait for MaxDetTime_c;
209	                check_equal(DataOut(0), IdleLevel_c, "Idle Value wrong after pulse");
210	            end if;
211	
212	            -- Bounce other signal constantly
213	            if run("BounceOtherSig") then
214	                -- bounce other signal
215	                BounceOhter <= true;
216	                -- Check initial state
217	                check_equal(DataOut(0), IdleLevel_c, "Wrong initial value");
218	                -- Toggle value
219	                DataAsync(0) <= not IdleLevel_c;
220	                -- Wait until value is detected
221	                if IsLowLat_c then
222	                    wait for MaxPropDelay_c;
223	                else
224	                    wait for MaxDetTime_c;
225	                end if;
226	                check_equal(DataOut(0), not IdleLevel_c, "Pulse Value wrong");
227	                -- wait for minimum time
228	                wait for MaxDetTime_c;
229	                -- End of pulse
230	                DataAsync(0) <= IdleLevel_c;
231	                -- Wait until new value is detected
232	                if IsLowLat_c then
233	                    wait for MaxPropDelay_c;
234	                else
235	                    wait for MaxDetTime_c;
236	                end if;
237	                check_equal(DataOut(0), IdleLevel_c, "Idle Value wrong after pulse");
238	                -- end bouncing other signal
239	                BounceOhter <= false;
240	            end if;
241	
242	            -- Delay between tests
243	            wait for 1 us;
244	            wait until rising_edge(Clk);
245	
246	        end loop;
247	
248	        -- TB done
249	        test_runner_cleanup(runner);
250	    end process;
251	
252	    -- Continuously bounce DataAsync(1) when requested by main process
253	    p_other : process is
254	    begin
255	        wait until rising_edge(Clk);
256	        if BounceOhter then
257	
258	            loop
259	                wait for Time_Debounce_c*0.1;
260	                DataAsync(1) <= not  DataAsync(1);
261	                if not BounceOhter then
262	                    exit;
263	                end if;
264	            end loop;
265	
266	            DataAsync(1) <= IdleLevel_c;
267	        end if;
268	    end process;
269	
270	end architecture;
